(function () {
    'use strict';

    function lockedProp(obj, key, value) {
        Object.defineProperty(obj, key, {
            get() { return value; },
            set() {  },
            configurable: false,
            enumerable: true
        });
    }

    window.aiptag = window.aiptag || {};
    window.aiptag.consented = true;
    window.aiptag.cmd = window.aiptag.cmd || [];
    window.aiptag.cmd.display = window.aiptag.cmd.display || [];
    window.aiptag.cmd.player = window.aiptag.cmd.player || [];
    lockedProp(window.aiptag.cmd.player, 'push', function (fn) {
        if (typeof fn === 'function') setTimeout(() => { try { fn(); } catch (e) {} }, 50);
    });

    lockedProp(window, 'aipPlayer', function (opts) {
        if (opts && typeof opts.AIP_COMPLETE === 'function') {
            setTimeout(() => { try { opts.AIP_COMPLETE(); } catch (e) {} }, 50);
        }
        return { destroy() {}, resize() {} };
    });

    const widgetStub = {
        isBlocked: 0,
        init() {},
        filter(s) { return s; },
        adsRefresh() {},
        createAdPlayer(onComplete) {
            setTimeout(() => { try { if (typeof onComplete === 'function') onComplete(); } catch (e) {} }, 50);
        },
        preroll() {
            setTimeout(() => { try { widgetStub.play(); } catch (e) {} }, 50);
        },
        play() {}
    };
    lockedProp(window, 'Widget', widgetStub);

    const BLOCK_SRC_PATTERN = /adinplay|aiptag|doubleclick|pagead|googlesyndication|prebid|onesignal|pushengage|truepush/i;

    function isBlockedUrl(v) {
        return typeof v === 'string' && BLOCK_SRC_PATTERN.test(v);
    }

    const origCreateElement = document.createElement.bind(document);
    document.createElement = function (tagName, ...rest) {
        const el = origCreateElement(tagName, ...rest);
        if (typeof tagName === 'string' && tagName.toLowerCase() === 'script') {
            const srcDesc = Object.getOwnPropertyDescriptor(HTMLScriptElement.prototype, 'src');
            Object.defineProperty(el, 'src', {
                get() { return srcDesc.get.call(el); },
                set(v) {
                    if (isBlockedUrl(v)) return;
                    srcDesc.set.call(el, v);
                },
                configurable: true
            });
        }
        return el;
    };

    const origSetAttribute = Element.prototype.setAttribute;
    Element.prototype.setAttribute = function (name, value) {
        if (this.tagName === 'SCRIPT' && name.toLowerCase() === 'src' && isBlockedUrl(value)) return;
        return origSetAttribute.call(this, name, value);
    };

    if (window.Notification) {
        try {
            Object.defineProperty(window.Notification, 'permission', { get: () => 'denied', configurable: true });
            window.Notification.requestPermission = function () {
                return Promise.resolve('denied');
            };
        } catch (e) {}
    }

    const REQUIRED_IDS = [
        'bebebaba', 'preroll', 'footer', 'chat', 'serverList',
        'changelog', 'howtoplay', 'featuredVideo', 'nickname', 'terms'
    ];

    function ensureRequiredElements() {
        const root = document.body || document.documentElement;
        if (!root) return;
        for (const id of REQUIRED_IDS) {
            if (!document.getElementById(id)) {
                const el = document.createElement.call(document, 'div');
                el.id = id;
                el.style.display = 'none';
                root.appendChild(el);
            }
        }
    }

    function cleanAdContent() {
        ['bebebaba', 'preroll'].forEach(id => {
            const el = document.getElementById(id);
            if (el) { el.innerHTML = ''; el.style.display = 'none'; }
        });
        const footer = document.getElementById('footer');
        if (footer) { footer.querySelectorAll('script').forEach(s => s.remove()); footer.style.display = 'none'; }
        document.querySelectorAll('[id^="devast-io_"]').forEach(el => el.remove());
    }

    const PROMPT_TEXT = /get the latest updates|don't miss out on news/i;
    const PROMPT_CLASS = /onesignal|slidedown|push-prompt|notification-prompt/i;

    function killPushPrompts(root = document) {
        root.querySelectorAll('[class],[id]').forEach(el => {
            const cls = (el.className && el.className.toString()) || '';
            const id = el.id || '';
            if (PROMPT_CLASS.test(cls) || PROMPT_CLASS.test(id)) { el.remove(); return; }
        });
        root.querySelectorAll('div,section,aside').forEach(el => {
            if (el.children.length < 12 && PROMPT_TEXT.test(el.textContent || '')) {
                el.remove();
            }
        });
    }

    function tick() {
        ensureRequiredElements();
        cleanAdContent();
        killPushPrompts();
    }

    if (document.readyState !== 'loading') tick();
    document.addEventListener('DOMContentLoaded', tick, { once: true });
    window.addEventListener('load', tick, { once: true });

    setInterval(tick, 50);
    setTimeout(() => { setInterval(tick, 500); }, 15000);

    const rootObserver = new MutationObserver(mutations => {
        for (const mutation of mutations) {
            for (const node of mutation.addedNodes) {
                if (node.nodeType !== Node.ELEMENT_NODE) continue;
                if (node.id && node.id.startsWith('devast-io_')) { node.remove(); continue; }
            }
        }
        killPushPrompts(document);
    });
    rootObserver.observe(document.documentElement, {
        childList: true,
        subtree: true,
        attributes: true,
        attributeFilter: ['class', 'style']
    });
})();
